+import type { MapSchema, ItemSchema } from '../index.js'
+
+type ObjectSchema = MapSchema | ItemSchema
+
+export const checkRequiredIf = (schema: ObjectSchema, path?: string): void => {
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    for (const requirement of attribute.props.requiredIf ?? []) {
+      const controllingAttribute = schema.attributes[requirement.attributeName]
+
+      if (controllingAttribute === undefined) {
+        throw new DynamoDBToolboxError('schema.requiredIf.invalidAttribute', {
+          message: `Invalid requiredIf attribute${path !== undefined ? ` at path '${path}'` : ''}: '${requirement.attributeName}' is not a sibling.`,
+          path,
+          payload: { attributeName, controllingAttributeName: requirement.attributeName }
+        })
+      }
+
+      if (requirement.attributeName === attributeName) {
+        throw new DynamoDBToolboxError('schema.requiredIf.selfReference', {
+          message: `Invalid requiredIf attribute${path !== undefined ? ` at path '${path}'` : ''}: '${attributeName}' cannot reference itself.`,
+          path,
+          payload: { attributeName }
+        })
+      }
+
+      if (attribute.props.key || controllingAttribute.props.key) {
+        throw new DynamoDBToolboxError('schema.requiredIf.keyAttribute', {
+          message: `Invalid requiredIf attribute${path !== undefined ? ` at path '${path}'` : ''}: key attributes cannot participate in requiredIf requirements.`,
+          path,
+          payload: { attributeName, controllingAttributeName: requirement.attributeName }
+        })
+      }
+    }
+  }
+}
+
+export const validateRequiredIf = (schema: ObjectSchema, value: Record<string, unknown>, path?: string): void => {
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    if (attribute.props.required === 'always' || value[attributeName] !== undefined) {
