    return expressOrCondition(condition, prefix, state)
  }

  if ('and' in condition) {
    return expressAndCondition(condition, prefix, state)
  }

  if ('not' in condition) {
    return expressNotCondition(condition, prefix, state)
  }

  if ('eq' in condition) {
    return expressEqCondition(condition, prefix, state)
  }

  if ('ne' in condition) {
