  }

  if ('gte' in condition) {
    return expressGteCondition(condition, prefix, state)
  }

  if ('gt' in condition) {
    return expressGtCondition(condition, prefix, state)
  }

  if ('lte' in condition) {
    return expressLteCondition(condition, prefix, state)
  }

  if ('lt' in condition) {
